package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.InputType
import android.view.View
import android.widget.Button
import android.widget.EditText
import android.widget.ProgressBar
import android.widget.TextView
import androidx.activity.ComponentActivity
import androidx.activity.result.contract.ActivityResultContracts
import androidx.annotation.MainThread
import androidx.appcompat.app.AlertDialog
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.core.widget.doAfterTextChanged
import androidx.lifecycle.DefaultLifecycleObserver
import androidx.lifecycle.LifecycleOwner
import java.util.concurrent.Executor

private const val PREFS_NAME = "auth_prefs"
private const val KEY_AUTHENTICATED = "authenticated"
private const val KEY_PASSWORD = "password"

object AuthPrefs {
    fun prefs(context: Context): SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun ensureDefaultPassword(context: Context) {
        val p = prefs(context)
        if (!p.contains(KEY_PASSWORD)) {
            p.edit().putString(KEY_PASSWORD, "password123").apply()
        }
    }

    fun verifyPassword(context: Context, input: String): Boolean {
        val stored = prefs(context).getString(KEY_PASSWORD, "password123") ?: "password123"
        return input == stored
    }

    fun setPassword(context: Context, newPassword: String) {
        prefs(context).edit().putString(KEY_PASSWORD, newPassword).apply()
    }

    fun logout(context: Context) {
        setAuthenticated(context, false)
    }
}

class LoginActivity : ComponentActivity() {

    private lateinit var executor: Executor
    private var biometricPrompt: BiometricPrompt? = null
    private var promptInfo: BiometricPrompt.PromptInfo? = null

    private lateinit var statusText: TextView
    private lateinit var biometricButton: Button
    private lateinit var passwordButton: Button
    private lateinit var passwordInput: EditText
    private lateinit var progress: ProgressBar

    private val enrollLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) {
        updateBiometricAvailabilityUi()
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        AuthPrefs.ensureDefaultPassword(this)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        setContentView(R.layout.activity_login)

        statusText = findViewById(R.id.statusText)
        biometricButton = findViewById(R.id.biometricButton)
        passwordButton = findViewById(R.id.passwordButton)
        passwordInput = findViewById(R.id.passwordInput)
        progress = findViewById(R.id.progress)

        executor = ContextCompat.getMainExecutor(this)

        setupBiometricPrompt()
        setupUi()

        updateBiometricAvailabilityUi()

        lifecycle.addObserver(object : DefaultLifecycleObserver {
            override fun onResume(owner: LifecycleOwner) {
                updateBiometricAvailabilityUi()
            }
        })
    }

    private fun setupUi() {
        progress.visibility = View.GONE

        passwordInput.inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        passwordInput.doAfterTextChanged {
            statusText.text = ""
        }

        biometricButton.setOnClickListener {
            statusText.text = ""
            showBiometric()
        }

        passwordButton.setOnClickListener {
            statusText.text = ""
            attemptPasswordLogin()
        }

        findViewById<TextView?>(R.id.forgotPasswordText)?.setOnClickListener {
            showPasswordHintDialog()
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onAuthenticated()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    statusText.text = errString
                    showPasswordFallbackInline()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusText.text = getString(R.string.biometric_not_recognized_try_again)
                    showPasswordFallbackInline()
                }
            }
        )

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(getString(R.string.biometric_title))
            .setSubtitle(getString(R.string.biometric_subtitle))
            .setConfirmationRequired(false)
            .setNegativeButtonText(getString(R.string.use_password))
            .build()
    }

    private fun updateBiometricAvailabilityUi() {
        val manager = BiometricManager.from(this)
        val can = manager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.BIOMETRIC_WEAK
        )

        when (can) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricButton.isEnabled = true
                biometricButton.visibility = View.VISIBLE
                statusText.text = getString(R.string.sign_in_quickly)
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                biometricButton.isEnabled = true
                biometricButton.visibility = View.VISIBLE
                statusText.text = getString(R.string.no_biometrics_enrolled)
                biometricButton.setOnClickListener {
                    statusText.text = ""
                    launchEnroll()
                }
            }
            else -> {
                biometricButton.isEnabled = false
                biometricButton.visibility = View.GONE
                statusText.text = getString(R.string.biometric_unavailable_use_password)
                showPasswordFallbackInline()
            }
        }
    }

    private fun launchEnroll() {
        val intent = Intent(android.provider.Settings.ACTION_BIOMETRIC_ENROLL).apply {
            putExtra(
                android.provider.Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                BiometricManager.Authenticators.BIOMETRIC_STRONG or
                    BiometricManager.Authenticators.BIOMETRIC_WEAK
            )
        }
        enrollLauncher.launch(intent)
    }

    private fun showBiometric() {
        val manager = BiometricManager.from(this)
        val can = manager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.BIOMETRIC_WEAK
        )
        if (can != BiometricManager.BIOMETRIC_SUCCESS) {
            showPasswordFallbackInline()
            return
        }
        biometricPrompt?.authenticate(requireNotNull(promptInfo))
    }

    @MainThread
    private fun onAuthenticated() {
        AuthPrefs.setAuthenticated(this, true)
        goHome()
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }

    private fun showPasswordFallbackInline() {
        passwordInput.visibility = View.VISIBLE
        passwordButton.visibility = View.VISIBLE
        if (passwordInput.text.isNullOrBlank()) passwordInput.requestFocus()
    }

    private fun attemptPasswordLogin() {
        showPasswordFallbackInline()
        val input = passwordInput.text?.toString()?.trim().orEmpty()
        if (input.isEmpty()) {
            statusText.text = getString(R.string.enter_password)
            return
        }

        progress.visibility = View.VISIBLE
        passwordButton.isEnabled = false
        biometricButton.isEnabled = false

        passwordInput.postDelayed({
            val ok = AuthPrefs.verifyPassword(this, input)
            progress.visibility = View.GONE
            passwordButton.isEnabled = true
            biometricButton.isEnabled = true

            if (ok) {
                onAuthenticated()
            } else {
                statusText.text = getString(R.string.wrong_password)
                passwordInput.setText("")
                passwordInput.requestFocus()
            }
        }, 250)
    }

    private fun showPasswordHintDialog() {
        AlertDialog.Builder(this)
            .setTitle(getString(R.string.password_help_title))
            .setMessage(getString(R.string.password_help_message))
            .setPositiveButton(android.R.string.ok, null)
            .show()
    }
}

class HomeActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (!AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        setContentView(R.layout.activity_home)

        findViewById<Button?>(R.id.logoutButton)?.setOnClickListener {
            AuthPrefs.logout(this)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}

